#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[5005];
        if (!fgets(line, sizeof(line), stdin)) line[0] = '\0';
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        long long arr[1005];
        int n = 0;
        char *token = strtok(line, " ");
        while (token) {
            arr[n++] = atoll(token);
            token = strtok(NULL, " ");
        }
        long long idx;
        if (scanf("%lld", &idx) != 1) idx = 0;
        getchar(); // consume newline after index
        if (idx >= 0 && idx < n) {
            printf("%lld\n", arr[idx]);
        } else {
            printf("Index out of range\n");
        }
    }
    return 0;
}

