code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String listLine = br.readLine();
            if (listLine == null) listLine = "";
            listLine = listLine.trim();
            List<Long> list = new ArrayList<>();
            if (!listLine.isEmpty()) {
                StringTokenizer st = new StringTokenizer(listLine);
                while (st.hasMoreTokens()) {
                    list.add(Long.parseLong(st.nextToken()));
                }
            }
            String idxLine = br.readLine();
            if (idxLine == null) idxLine = "0";
            long idx = Long.parseLong(idxLine.trim());
            if (idx >= 0 && idx < list.size()) {
                out.append(list.get((int) idx)).append('\n');
            } else {
                out.append("Index out of range").append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

