#!/usr/bin/env python3
import sys

def safe_access(arr, idx):
    try:
        return str(arr[idx])
    except IndexError:
        return "Index out of range"

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    out = []
    line = 1
    for _ in range(t):
        lst_line = data[line].strip() if line < len(data) else ""
        line += 1
        arr = list(map(int, lst_line.split())) if lst_line else []
        idx = int(data[line].strip()) if line < len(data) else 0
        line += 1
        out.append(safe_access(arr, idx))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

